import { Connection, PublicKey, Transaction, SystemProgram, LAMPORTS_PER_SOL } from '@solana/web3.js';
import { 
    NATIVE_MINT,
    getAssociatedTokenAddress,
    createCloseAccountInstruction,
    getAccount
} from '@solana/spl-token';

export async function executeSkill(blockhash: string): Promise<string> {
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey('Apx3RqyE47o1yxDtZ3iC9pHtNsQxUg4H3YYLtYjXSkc6');

    const wsolAta = await getAssociatedTokenAddress(NATIVE_MINT, agentPubkey);

    const tx = new Transaction();

    // Check if the Wrapped SOL ATA exists and has a balance
    // If it doesn't exist or is empty, closing it will fail.
    try {
        const wsolAccount = await getAccount(connection, wsolAta);
        if (wsolAccount.amount === 0n) {
            throw new Error("Wrapped SOL ATA exists but has zero balance. Cannot unwrap.");
        }
    } catch (e) {
        if (e.name === 'TokenAccountNotFoundError') {
            throw new Error("Wrapped SOL ATA not found for agent. Cannot unwrap.");
        } else {
            throw e; // Re-throw other errors
        }
    }

    // Create a close account instruction for the Wrapped SOL ATA
    // This will unwrap the SOL and return the balance to the owner (agentPubkey)
    tx.add(createCloseAccountInstruction(
        wsolAta,          // Token account to close
        agentPubkey,      // Destination for the SOL (owner)
        agentPubkey       // Owner of the token account
    ));

    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey; 

    // The agentPubkey is the only signer required, and the environment handles it.

    return tx.serialize({ requireAllSignatures: false }).toString('base64');
}
