import { Connection, PublicKey, Transaction, SystemProgram, LAMPORTS_PER_SOL } from '@solana/web3.js';
import { 
    NATIVE_MINT,
    getAssociatedTokenAddress,
    createAssociatedTokenAccountInstruction,
    createSyncNativeInstruction,
    createTransferInstruction,
    getAccount
} from '@solana/spl-token';

export async function executeSkill(blockhash: string): Promise<string> {
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey('Apx3RqyE47o1yxDtZ3iC9pHtNsQxUg4H3YYLtYjXSkc6');

    // Get the agent's WSOL ATA
    const agentWsolAta = await getAssociatedTokenAddress(NATIVE_MINT, agentPubkey);

    const tx = new Transaction();

    // 1. Create WSOL ATA for the agent (idempotent)
    tx.add(createAssociatedTokenAccountInstruction(
        agentPubkey, // Payer
        agentWsolAta, 
        agentPubkey, // Owner
        NATIVE_MINT
    ));

    // 2. Transfer SOL to the WSOL ATA and Sync Native
    const amountToFundWsolAta = 0.005 * LAMPORTS_PER_SOL; // Fund with 0.005 SOL

    tx.add(SystemProgram.transfer({
        fromPubkey: agentPubkey,
        toPubkey: agentWsolAta,
        lamports: amountToFundWsolAta,
    }));
    tx.add(createSyncNativeInstruction(agentWsolAta));

    // 3. Perform the self-transfer of WSOL
    // Transfer a tiny amount of WSOL from agent's ATA to agent's *own* ATA
    const amountToTransfer = 0.0001 * LAMPORTS_PER_SOL; // 0.0001 WSOL

    tx.add(createTransferInstruction(
        agentWsolAta,       // Source ATA (agent's WSOL)
        agentWsolAta,       // Destination ATA (agent's own WSOL ATA)
        agentPubkey,        // Owner/Authority of the source ATA (agent)
        amountToTransfer    // Amount to transfer
    ));

    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey; 

    // The agentPubkey needs to sign as the owner of the source ATA.

    return tx.serialize({ requireAllSignatures: false }).toString('base64');
}
