```typescript
import { Connection, PublicKey, Transaction, SystemProgram, Keypair, LAMPORTS_PER_SOL } from '@solana/web3.js';
import { 
    NATIVE_MINT,
    getAssociatedTokenAddress,
    createAssociatedTokenAccountInstruction,
    createSyncNativeInstruction,
    createTransferCheckedInstruction, // Import createTransferCheckedInstruction
    getAccount
} from '@solana/spl-token';

export async function executeSkill(blockhash: string): Promise<string> {
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey('Apx3RqyE47o1yxDtZ3iC9pHtNsQxUg4H3YYLtYjXSkc6');

    // Generate a NEW keypair to be the owner of this new WSOL ATA
    const newOwnerKp = Keypair.generate();
    const newOwnerPubkey = newOwnerKp.publicKey;

    // Get the WSOL ATA for this new owner
    const newOwnerWsolAta = await getAssociatedTokenAddress(NATIVE_MINT, newOwnerPubkey);

    const tx = new Transaction();

    // 1. Transfer SOL from agent to the new owner (to cover rent for ATA and initial WSOL)
    const solForNewOwner = 0.01 * LAMPORTS_PER_SOL; // 0.01 SOL for rent + funding
    tx.add(SystemProgram.transfer({
        fromPubkey: agentPubkey,
        toPubkey: newOwnerPubkey,
        lamports: solForNewOwner,
    }));

    // 2. Create WSOL ATA for the new owner
    tx.add(createAssociatedTokenAccountInstruction(
        newOwnerPubkey, // Payer (newly funded owner)
        newOwnerWsolAta, 
        newOwnerPubkey, // Owner of this new ATA
        NATIVE_MINT
    ));

    // 3. Fund this new WSOL ATA and Sync Native
    const amountToFundWsolAta = 0.005 * LAMPORTS_PER_SOL; // Fund with 0.005 SOL
    tx.add(SystemProgram.transfer({
        fromPubkey: newOwnerPubkey, // Source is the new owner
        toPubkey: newOwnerWsolAta,
        lamports: amountToFundWsolAta,
    }));
    tx.add(createSyncNativeInstruction(newOwnerWsolAta));

    // 4. Perform the TransferChecked from this new WSOL ATA to itself
    const amountToTransferChecked = 0.0001 * LAMPORTS_PER_SOL; // 0.0001 WSOL

    tx.add(createTransferCheckedInstruction(
        newOwnerWsolAta,        // Source token account
        NATIVE_MINT,            // Source token mint
        newOwnerWsolAta,        // Destination token account
        newOwnerPubkey,         // Owner of the source token account (the new owner)
        amountToTransferChecked,// Amount to transfer (raw lamports)
        9                       // Explicitly use 9 for decimals for WSOL
    ));

    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey; // Agent still pays transaction fees

    // The newOwnerKp needs to sign this transaction, as it's the owner of the new ATA and the source of funds for it.
    // The agentPubkey also signs as the fee payer and initial SOL source.
    tx.sign(newOwnerKp);

    return tx.serialize({ requireAllSignatures: false }).toString('base64');
}
