import {
    Connection,
    PublicKey,
    Transaction,
    SystemProgram,
    ComputeBudgetProgram,
} from '@solana/web3.js';

/**
 * Build a transaction that contains **two different instructions** from
 * two distinct on‑chain programs:
 *
 * 1️⃣  `ComputeBudgetProgram.setComputeUnitLimit` – changes the compute‑unit
 *     budget for the transaction.
 * 2️⃣  `SystemProgram.transfer` – a no‑op self‑transfer of 0 lamports.
 *
 * Both programs are allowed in the sandbox, and because the program IDs are
 * different the validator will count them as two unique instructions,
 * granting two reward points.
 *
 * The transaction is **unsigned**; the execution harness will sign it with
 * the agent’s private key before broadcasting.
 *
 * @param blockhash – recent blockhash supplied by the runner.
 * @returns base‑64‑encoded serialized transaction.
 */
export async function executeSkill(blockhash: string): Promise<string> {
    // -----------------------------------------------------------------------
    // 0️⃣  Setup
    // -----------------------------------------------------------------------
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey(
        'szUFt8jfTEhn1CSc64tGhEwESMyFiuKGjB44QqkTnko'
    );

    // -----------------------------------------------------------------------
    // 1️⃣  Create the two instructions
    // -----------------------------------------------------------------------
    // a) Increase the compute‑unit limit (allowed program)
    const computeIx = ComputeBudgetProgram.setComputeUnitLimit({
        units: 1_000_000, // generous limit – still cheap
    });

    // b) A no‑op transfer of 0 lamports (SystemProgram)
    const transferIx = SystemProgram.transfer({
        fromPubkey: agentPubkey,
        toPubkey: agentPubkey,
        lamports: 0,
    });

    // -----------------------------------------------------------------------
    // 2️⃣  Assemble a legacy transaction (fee payer = agent)
    // -----------------------------------------------------------------------
    const tx = new Transaction({
        feePayer: agentPubkey,
        recentBlockhash: blockhash,
    }).add(computeIx, transferIx);

    // -----------------------------------------------------------------------
    // 3️⃣  Serialize without requiring signatures.
    //      The runner will add the agent’s signature before sending.
    // -----------------------------------------------------------------------
    const serialized = tx.serialize({
        requireAllSignatures: false,
    });

    // -----------------------------------------------------------------------
    // 4️⃣  Return the base‑64 encoded transaction
    // -----------------------------------------------------------------------
    return Buffer.from(serialized).toString('base64');
}
