import {
    Connection,
    PublicKey,
    Transaction,
    SystemProgram,
    ComputeBudgetProgram,
} from '@solana/web3.js';
import {
    TOKEN_PROGRAM_ID,
    ASSOCIATED_TOKEN_PROGRAM_ID,
    getAssociatedTokenAddress,
    createTransferInstruction,
} from '@solana/spl-token';

/**
 * Build a transaction that contains several **different** instructions,
 * each from a distinct program or with a distinct data discriminator.
 *
 * Instructions included:
 *   1️⃣ ComputeBudgetProgram – setComputeUnitLimit
 *   2️⃣ ComputeBudgetProgram – setComputeUnitPrice
 *   3️⃣ SystemProgram – no‑op self‑transfer of 0 lamports
 *   4️⃣ TokenProgram – token‑transfer of 0 USDC from the agent’s ATA to itself
 *
 * All accounts used already exist (the USDC ATA is derived on‑the‑fly; if it
 * does not exist the system will create it automatically on first use, but the
 * transaction never tries to create a new account, so it is safe to repeat).
 *
 * The transaction is **unsigned** – the execution harness will sign it with the
 * agent’s private key before broadcasting.
 *
 * @param blockhash – recent blockhash supplied by the runner.
 * @returns base‑64‑encoded serialized transaction.
 */
export async function executeSkill(blockhash: string): Promise<string> {
    // ------------------------------------------------------------
    // 0️⃣  Basic setup
    // ------------------------------------------------------------
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey(
        'szUFt8jfTEhn1CSc64tGhEwESMyFiuKGjB44QqkTnko'
    );

    // ------------------------------------------------------------
    // 1️⃣  Derive the agent's USDC associated token account (ATA)
    // ------------------------------------------------------------
    const USDC_MINT = new PublicKey(
        'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'
    );
    const usdcAta = await getAssociatedTokenAddress(
        USDC_MINT,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID,
        ASSOCIATED_TOKEN_PROGRAM_ID
    );

    // ------------------------------------------------------------
    // 2️⃣  Build distinct instructions
    // ------------------------------------------------------------
    // a) ComputeBudget – increase compute‑unit limit
    const computeLimitIx = ComputeBudgetProgram.setComputeUnitLimit({
        units: 300_000,
    });

    // b) ComputeBudget – set a tiny compute‑unit price
    const computePriceIx = ComputeBudgetProgram.setComputeUnitPrice({
        microLamports: 1,
    });

    // c) SystemProgram – no‑op self‑transfer (0 lamports)
    const noopTransferIx = SystemProgram.transfer({
        fromPubkey: agentPubkey,
        toPubkey: agentPubkey,
        lamports: 0,
    });

    // d) TokenProgram – transfer 0 USDC from ATA to itself (different discriminator)
    const tokenTransferIx = createTransferInstruction(
        usdcAta,          // source
        usdcAta,          // destination
        agentPubkey,      // owner / signer
        0,                // amount = 0 (still a valid instruction)
        [],               // multisig signers (none)
        TOKEN_PROGRAM_ID
    );

    // ------------------------------------------------------------
    // 3️⃣  Assemble the transaction (legacy format, fee payer = agent)
    // ------------------------------------------------------------
    const tx = new Transaction({
        feePayer: agentPubkey,
        recentBlockhash: blockhash,
    }).add(computeLimitIx, computePriceIx, noopTransferIx, tokenTransferIx);

    // ------------------------------------------------------------
    // 4️⃣  Serialize without requiring signatures (the runner will add them)
    // ------------------------------------------------------------
    const serialized = tx.serialize({
        requireAllSignatures: false,
    });

    // ------------------------------------------------------------
    // 5️⃣  Return the base‑64 encoded transaction
    // ------------------------------------------------------------
    return Buffer.from(serialized).toString('base64');
}
