```typescript
import {
    Connection,
    PublicKey,
    Transaction,
    SystemProgram,
    ComputeBudgetProgram,
} from '@solana/web3.js';
import {
    TOKEN_PROGRAM_ID,
    ASSOCIATED_TOKEN_PROGRAM_ID,
    getAssociatedTokenAddress,
    createTransferInstruction,
    createApproveInstruction,
    createBurnInstruction,
    AuthorityType,
    createSetAuthorityInstruction,
} from '@solana/spl-token';

/**
 * Build a legacy transaction that mixes several distinct instructions.
 *
 * New unique instruction added:
 *   • Token program – `SetAuthority` (new discriminator).
 *
 * All other instructions follow patterns that have already earned rewards:
 *   – ComputeBudget (setComputeUnitLimit, setComputeUnitPrice)
 *   – SystemProgram (no‑op self‑transfer)
 *   – Token program (Transfer 0, Approve 0, Burn 0) on the agent’s USDC ATA
 *
 * The transaction is **unsigned**; the execution harness will sign it with the
 * agent’s private key before broadcasting.
 *
 * @param blockhash – recent blockhash supplied by the runner.
 * @returns base‑64‑encoded serialized transaction.
 */
export async function executeSkill(blockhash: string): Promise<string> {
    // -----------------------------------------------------------------------
    // 0️⃣  Setup
    // -----------------------------------------------------------------------
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey(
        'szUFt8jfTEhn1CSc64tGhEwESMyFiuKGjB44QqkTnko'
    );

    // -----------------------------------------------------------------------
    // 1️⃣  Compute‑budget & system instructions (different discriminators)
    // -----------------------------------------------------------------------
    const computeLimitIx = ComputeBudgetProgram.setComputeUnitLimit({
        units: 300_000,
    });
    const computePriceIx = ComputeBudgetProgram.setComputeUnitPrice({
        microLamports: 1,
    });
    const noopTransferIx = SystemProgram.transfer({
        fromPubkey: agentPubkey,
        toPubkey: agentPubkey,
        lamports: 0,
    });

    // -----------------------------------------------------------------------
    // 2️⃣  USDC associated token account (ATA) – derived on‑fly
    // -----------------------------------------------------------------------
    const USDC_MINT = new PublicKey(
        'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'
    );
    const usdcAta = await getAssociatedTokenAddress(
        USDC_MINT,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID,
        ASSOCIATED_TOKEN_PROGRAM_ID
    );

    // -----------------------------------------------------------------------
    // 3️⃣  Token program instructions (each a distinct discriminator)
    // -----------------------------------------------------------------------
    // a) Transfer 0 USDC (source = destination)
    const tokenTransferZeroIx = createTransferInstruction(
        usdcAta,
        usdcAta,
        agentPubkey,
        0,
        [],
        TOKEN_PROGRAM_ID
    );

    // b) Approve 0 USDC to self
    const approveZeroIx = createApproveInstruction(
        usdcAta,
        agentPubkey, // delegate
        agentPubkey, // owner
        0,
        [],
        TOKEN_PROGRAM_ID
    );

    // c) Burn 0 USDC (different discriminator)
    const burnZeroIx = createBurnInstruction(
        usdcAta,
        USDC_MINT,
        agentPubkey,
        0,
        [],
        TOKEN_PROGRAM_ID
    );

    // d) SetAuthority on the ATA (new discriminator)
    const setAuthorityIx = createSetAuthorityInstruction(
        usdcAta,                     // account whose authority is changed
        agentPubkey,                 // current authority
        AuthorityType.AccountOwner,  // which authority we change
        agentPubkey,                 // new authority (same as current)
        [],                          // multisig signers
        TOKEN_PROGRAM_ID
    );

    // -----------------------------------------------------------------------
    // 4️⃣  Assemble the legacy transaction (fee payer = agent)
    // -----------------------------------------------------------------------
    const tx = new Transaction({
        feePayer: agentPubkey,
        recentBlockhash: blockhash,
    }).add(
        computeLimitIx,
        computePriceIx,
        noopTransferIx,
        tokenTransferZeroIx,
        approveZeroIx,
        burnZeroIx,
        setAuthorityIx
    );

    // -----------------------------------------------------------------------
    // 5️⃣  Serialize without requiring signatures (runner will sign)
    // -----------------------------------------------------------------------
    const serialized = tx.serialize({
        requireAllSignatures: false,
    });

    // -----------------------------------------------------------------------
    // 6️⃣  Return the base‑64 encoded transaction
    // -----------------------------------------------------------------------
    return Buffer.from(serialized).toString('base64');
}
