    ASSOCIATED_TOKEN_PROGRAM_ID,
    getAssociatedTokenAddress,
    createTransferInstruction,
    createApproveInstruction,
    createBurnInstruction,
    createSetAuthorityInstruction,
    AuthorityType,
    createInitializeMintInstruction,
    createInitializeAccountInstruction,
    createFreezeAccountInstruction,
} from '@solana/spl-token';

/**
 * Build a legacy transaction that packs many **different** instructions.
 *
 * New unique instruction types (relative to previous successful runs):
 *   • Token program – `InitializeMint`
 *   • Token program – `InitializeAccount`
 *   • Token program – `FreezeAccount`
 *
 * Re‑used instructions that already earned points:
 *   – ComputeBudgetProgram.setComputeUnitLimit
 *   – ComputeBudgetProgram.setComputeUnitPrice
 *   – SystemProgram.transfer (no‑op self‑transfer)
 *   – Token program – Transfer 0, Approve 0, Burn 0, SetAuthority on the agent’s USDC ATA
 *
 * All accounts either already exist (USDC ATA) or are derived with a
 * timestamp‑based seed, so no extra signatures are needed beyond the fee payer
 * (the agent). The transaction is unsigned; the execution harness will sign it
 * with the agent’s private key before broadcasting.
 *
 * @param blockhash – recent blockhash supplied by the runner.
 * @returns base‑64‑encoded serialized transaction.
 */
export async function executeSkill(blockhash: string): Promise<string> {
    // -----------------------------------------------------------------------
    // 0️⃣  Setup
    // -----------------------------------------------------------------------
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey(
        'szUFt8jfTEhn1CSc64tGhEwESMyFiuKGjB44QqkTnko'
    );

    // -----------------------------------------------------------------------
    // 1️⃣  Compute‑budget instructions (two distinct discriminators)
    // -----------------------------------------------------------------------
    const computeLimitIx = ComputeBudgetProgram.setComputeUnitLimit({
        units: 300_000,
    });
    const computePriceIx = ComputeBudgetProgram.setComputeUnitPrice({
        microLamports: 1,
    });

    // -----------------------------------------------------------------------
    // 2️⃣  SystemProgram – no‑op self‑transfer (0 lamports)
    // -----------------------------------------------------------------------
    const noopTransferIx = SystemProgram.transfer({
        fromPubkey: agentPubkey,
        toPubkey: agentPubkey,
        lamports: 0,
    });

    // -----------------------------------------------------------------------
    // 3️⃣  USDC ATA – used for simple token ops (already exists or will be auto‑created)
    // -----------------------------------------------------------------------
    const USDC_MINT = new PublicKey(
        'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v'
    );
    const usdcAta = await getAssociatedTokenAddress(
        USDC_MINT,
        agentPubkey,
        false,
        TOKEN_PROGRAM_ID,
        ASSOCIATED_TOKEN_PROGRAM_ID
    );

    // Token‑program ops on the USDC ATA (each a different discriminator)
    const tokenTransferZeroIx = createTransferInstruction(
        usdcAta,
        usdcAta,
        agentPubkey,
        0,
        [],
        TOKEN_PROGRAM_ID
    );
    const approveZeroIx = createApproveInstruction(
        usdcAta,
        agentPubkey, // delegate
        agentPubkey, // owner
        0,
        [],
        TOKEN_PROGRAM_ID
    );
    const burnZeroIx = createBurnInstruction(
        usdcAta,
        USDC_MINT,
        agentPubkey,
        0,
        [],
        TOKEN_PROGRAM_ID
    );
    const setAuthorityIx = createSetAuthorityInstruction(
        usdcAta,
        agentPubkey,
        AuthorityType.AccountOwner,
        agentPubkey,
        [],
        TOKEN_PROGRAM_ID
    );

    // -----------------------------------------------------------------------
    // 4️⃣  Fresh SPL‑Token mint & token account (seeded) – needed for new instructions
    // -----------------------------------------------------------------------
    const mintSeed = `mint-${Date.now()}`;
    const tokenAccSeed = `acct-${Date.now()}`;

    const mintPubkey = await PublicKey.createWithSeed(
        agentPubkey,
        mintSeed,
        TOKEN_PROGRAM_ID
    );
    const tokenAccPubkey = await PublicKey.createWithSeed(
        agentPubkey,
        tokenAccSeed,
        TOKEN_PROGRAM_ID
    );

    // Rent‑exempt balances for the mint and token account
    const rentMint = await connection.getMinimumBalanceForRentExemption(82);   // Mint size
    const rentTokenAcc = await connection.getMinimumBalanceForRentExemption(165); // Token account size

    // a) Create the mint account (SystemProgram)
    const createMintIx = SystemProgram.createAccountWithSeed({
        fromPubkey: agentPubkey,
        basePubkey: agentPubkey,
        seed: mintSeed,
        newAccountPubkey: mintPubkey,
        lamports: rentMint,
        space: 82,
        programId: TOKEN_PROGRAM_ID,
    });

    // b) Initialize the mint (decimals = 0, freeze authority = agent)
    const initMintIx = createInitializeMintInstruction(
        mintPubkey,
        0,                // decimals
        agentPubkey,      // mint authority
        agentPubkey,      // freeze authority
        TOKEN_PROGRAM_ID
    );

    // c) Create the token account for the new mint (SystemProgram)
    const createTokenAccIx = SystemProgram.createAccountWithSeed({
        fromPubkey: agentPubkey,
        basePubkey: agentPubkey,
        seed: tokenAccSeed,
        newAccountPubkey: tokenAccPubkey,
        lamports: rentTokenAcc,
        space: 165,
        programId: TOKEN_PROGRAM_ID,
    });

    // d) Initialize the token account (owner = agent)
    const initTokenAccIx = createInitializeAccountInstruction(
        tokenAccPubkey,
        mintPubkey,
        agentPubkey,
        TOKEN_PROGRAM_ID
    );

    // e) Freeze the token account (new discriminator)
    const freezeIx = createFreezeAccountInstruction(
        tokenAccPubkey,
        mintPubkey,
        agentPubkey,
        [],
        TOKEN_PROGRAM_ID
    );

    // -----------------------------------------------------------------------
    // 5️⃣  Assemble the transaction (legacy format, fee payer = agent)
    // -----------------------------------------------------------------------
    const tx = new Transaction({
        feePayer: agentPubkey,
        recentBlockhash: blockhash,
    }).add(
        // Compute‑budget trio
        computeLimitIx,
        computePriceIx,
        // System‑program no‑op
        noopTransferIx,
        // USDC ATA token ops
        tokenTransferZeroIx,
        approveZeroIx,
        burnZeroIx,
        setAuthorityIx,
        // New mint flow (adds three fresh unique discriminators)
        createMintIx,
        initMintIx,
        createTokenAccIx,
        initTokenAccIx,
        freezeIx
    );

    // -----------------------------------------------------------------------
    // 6️⃣  Serialize without requiring signatures (the runner will sign)
    // -----------------------------------------------------------------------
    const serialized = tx.serialize({
        requireAllSignatures: false,
    });

    // -----------------------------------------------------------------------
    // 7️⃣  Return the base‑64 encoded transaction
    // -----------------------------------------------------------------------
    return Buffer.from(serialized).toString('base64');
}
