import { Connection, PublicKey, VersionedTransaction, Transaction } from '@solana/web3.js';
import { NATIVE_MINT } from '@solana/spl-token';

const AGENT = new PublicKey('9x69hUa2VVyCrbjuwT9b7K9pi8Mgn1xfCPjhBVeX76mL');
const SOL = NATIVE_MINT.toBase58();
const USDC = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v';
const USDT = 'Es9vMFrzaCERmJfrF4H2FYD4KCoNkY11McCe8BenwNYB';
const JUP  = 'JUPyiwrYJFskUPiHa7hkeR8VUtAeFoSYbKedZNsDvCN';

function retargetBlockhash(txB64: string, blockhash: string): string {
  const buf = Buffer.from(txB64, 'base64');
  // Try versioned first
  try {
    const vtx = VersionedTransaction.deserialize(buf);
    vtx.message.recentBlockhash = blockhash;
    return Buffer.from(vtx.serialize()).toString('base64');
  } catch {
    // Fallback to legacy
    const ltx = Transaction.deserialize(buf);
    ltx.recentBlockhash = blockhash;
    ltx.feePayer = AGENT;
    return ltx.serialize({ requireAllSignatures: false }).toString('base64');
  }
}

async function jupiterSwap(params: {
  blockhash: string;
  inputMint: string;
  outputMint: string;
  amount: string; // base units: ExactIn = input amount, ExactOut = output amount
  slippageBps: number;
  swapMode: 'ExactIn' | 'ExactOut';
  asLegacy?: boolean;
  preferDexes?: string;
  excludeDexes?: string;
  onlyDirectRoutes?: boolean;
}): Promise<string> {
  const {
    blockhash,
    inputMint,
    outputMint,
    amount,
    slippageBps,
    swapMode,
    asLegacy = true,
    preferDexes,
    excludeDexes,
    onlyDirectRoutes,
  } = params;

  const qs = new URLSearchParams({
    inputMint,
    outputMint,
    amount,
    slippageBps: String(slippageBps),
    swapMode,
  });
  if (preferDexes) qs.set('preferDexes', preferDexes);
  if (excludeDexes) qs.set('excludeDexes', excludeDexes);
  if (onlyDirectRoutes !== undefined) qs.set('onlyDirectRoutes', onlyDirectRoutes ? 'true' : 'false');

  const quoteRes = await fetch('https://quote-api.jup.ag/v6/quote?' + qs.toString());
  if (!quoteRes.ok) throw new Error(`Jupiter quote HTTP ${quoteRes.status} ${quoteRes.statusText}`);
  const quote = await quoteRes.json();

  if (!quote || !quote.routePlan || (!quote.outAmount && swapMode === 'ExactIn')) {
    throw new Error(`Unexpected Jupiter quote: ${JSON.stringify(quote)}`);
  }

  const swapRes = await fetch('https://quote-api.jup.ag/v6/swap', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse: quote,
      userPublicKey: AGENT.toBase58(),
      wrapAndUnwrapSol: true,
      dynamicComputeUnitLimit: true,
      prioritizationFeeLamports: 'auto',
      asLegacyTransaction: asLegacy,
    }),
  });
  if (!swapRes.ok) throw new Error(`Jupiter swap HTTP ${swapRes.status} ${swapRes.statusText}`);
  const swapJson = await swapRes.json();
  if (!swapJson?.swapTransaction) throw new Error(`Jupiter swap build failed: ${JSON.stringify(swapJson)}`);

  return retargetBlockhash(swapJson.swapTransaction, blockhash);
}

export async function executeSkill(blockhash: string): Promise<string> {
  // Maintain connection per environment guidance
  const _connection = new Connection('http://localhost:8899');

  // Try to exercise new routes:
