export async function executeSkill(blockhash: string): Promise<string> {
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey('9JHtyZY3cE63anUuh4YKR5WmeuhrRR2a63atJpDHWdip');

    // A well-known public key to transfer SOL to (e.g., USDC mint address)
    const recipientPubkey = new PublicKey('EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v');

    const amount = 0.001 * LAMPORTS_PER_SOL; // 0.001 SOL

    const tx = new Transaction();

    tx.add(
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: recipientPubkey,
            lamports: amount,
        })
    );

    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // The environment will handle signing with the agent's keypair.
    return tx.serialize({ requireAllSignatures: false }).toString('base64');
