    getAssociatedTokenAddress,
    TOKEN_PROGRAM_ID,
    createMintToInstruction // New instruction: non-checked mint
} from '@solana/spl-token';

export async function executeSkill(blockhash: string): Promise<string> {
    const connection = new Connection('http://localhost:8899');
    const agentPubkey = new PublicKey('9JHtyZY3cE63anUuh4YKR5WmeuhrRR2a63atJpDHWdip');

    // --- Step 1: Create a new custom token and its ATA for the agent ---
    const mintAuthority = Keypair.generate();
    const customTokenMint = Keypair.generate(); // The new token's mint address

    const requiredBalance = await getMinimumBalanceForRentExemptMint(connection);

    const tx = new Transaction();
    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    // Create custom token mint account
    tx.add(
        SystemProgram.createAccount({
            fromPubkey: agentPubkey,
            newAccountPubkey: customTokenMint.publicKey,
            space: MINT_SIZE,
            lamports: requiredBalance,
            programId: TOKEN_PROGRAM_ID,
        })
    );

    // Initialize custom token mint
    tx.add(
        createInitializeMintInstruction(
            customTokenMint.publicKey, // Mint Address
            6, // Decimals
            mintAuthority.publicKey, // Mint Authority
            null, // Freeze Authority
            TOKEN_PROGRAM_ID
        )
    );

    // Get agent's ATA for the new custom token
    const agentCustomTokenAta = await getAssociatedTokenAddress(
        customTokenMint.publicKey, agentPubkey
    );

    // Create agent's ATA (idempotent)
    tx.add(
        createAssociatedTokenAccountInstruction(
            agentPubkey, // Payer
            agentCustomTokenAta, // ATA to create
            agentPubkey, // Owner of the ATA
            customTokenMint.publicKey // Mint for the ATA
        )
    );

    // --- Step 2: Mint some tokens to agent's ATA using non-checked instruction ---
    const amountToMint = 10 * (10 ** 6); // Mint 10 tokens
    tx.add(
        createMintToInstruction( // Using non-checked version
            customTokenMint.publicKey, // Mint Address
            agentCustomTokenAta, // Destination ATA (agent's)
            mintAuthority.publicKey, // Mint Authority
            amountToMint, // Amount to mint
            [], // Signers
            TOKEN_PROGRAM_ID
        )
    );

    // Sign with customTokenMint and mintAuthority keypairs.
    tx.sign(customTokenMint, mintAuthority); 

    return tx.serialize({ requireAllSignatures: false }).toString('base64');
}
