async function jupBuildLegacySwap(agent: PublicKey, blockhash: string, quoteResponse: any): Promise<string> {
  const swapRes = await fetch('https://quote-api.jup.ag/v6/swap', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      quoteResponse,
      userPublicKey: agent.toBase58(),
      asLegacyTransaction: true,       // keep small; avoid ALT size issues
      wrapAndUnwrapSol: true,          // handle SOL wrapping
      dynamicComputeUnitLimit: true,
      prioritizationFeeLamports: 'auto'
    })
  });
  const swapJson = await swapRes.json();
  if (!swapRes.ok || !swapJson?.swapTransaction) {
    throw new Error(`Jupiter swap build failed: ${JSON.stringify(swapJson)}`);
  }
  const tx = Transaction.from(Buffer.from(swapJson.swapTransaction, 'base64'));
  tx.recentBlockhash = blockhash;
  tx.feePayer = agent;
  return tx.serialize({ requireAllSignatures: false }).toString('base64');
}

