    // 1. Ensure Wrapped SOL ATA exists and is funded
    const agentWrappedSolAta = await getAssociatedTokenAddress(NATIVE_MINT, agentPubkey);
    let currentWrappedSolBalance = 0;
    const agentWrappedSolAccountInfo = await connection.getAccountInfo(agentWrappedSolAta);
    if (agentWrappedSolAccountInfo === null) {
        tx.add(createAssociatedTokenAccountInstruction(agentPubkey, agentWrappedSolAta, agentPubkey, NATIVE_MINT));
    } else {
        try {
            const tokenAccount = await connection.getTokenAccountBalance(agentWrappedSolAta);
            currentWrappedSolBalance = parseFloat(tokenAccount.value.amount) / (10 ** tokenAccount.value.decimals);
        } catch (e) {
            console.warn("Could not get Wrapped SOL ATA balance, assuming 0 for funding purposes.", e);
            currentWrappedSolBalance = 0;
        }
    }

    const swapAmountSol = 0.001; // Amount of SOL to swap
    const requiredWrappedSol = swapAmountSol;
    const bufferAmount = 0.001;
    const totalRequired = requiredWrappedSol + bufferAmount;

    if (currentWrappedSolBalance < totalRequired) {
        const amountToDepositLamports = Math.ceil((totalRequired - currentWrappedSolBalance) * LAMPORTS_PER_SOL);
        if (amountToDepositLamports > 0) {
            console.log(`Depositing ${amountToDepositLamports / LAMPORTS_PER_SOL} SOL into agent's Wrapped SOL ATA.`);
            tx.add(
                SystemProgram.transfer({
                    fromPubkey: agentPubkey,
                    toPubkey: agentWrappedSolAta,
                    lamports: amountToDepositLamports,
                }),
                createSyncNativeInstruction(agentWrappedSolAta)
            );
        }
    }

    // 2. Ensure RAY ATA exists
    const agentRayAta = await getAssociatedTokenAddress(RAY_MINT, agentPubkey);
    const rayAccountInfo = await connection.getAccountInfo(agentRayAta);
    if (rayAccountInfo === null) {
        console.log("Creating RAY ATA for agent...");
        tx.add(createAssociatedTokenAccountInstruction(
            agentPubkey,
            agentRayAta,
            agentPubkey,
            RAY_MINT
        ));
    }

    // 1. Get quote from Jupiter (SOL to RAY)
    const quoteResponse = await fetch(
        'https://quote-api.jup.ag/v6/quote?' +
        new URLSearchParams({
            inputMint: NATIVE_MINT.toString(),
            outputMint: RAY_MINT.toString(), // Swap to RAY
            amount: (swapAmountSol * LAMPORTS_PER_SOL).toString(),
            slippageBps: '10000' // 100% slippage
        })
    );

    const quote = await quoteResponse.json();

    if (quote.error) {
        throw new Error(`Jupiter Quote error: ${quote.error}`);
    }

    // 2. Get swap instructions from Jupiter
    const swapInstructionsResponse = await fetch('https://quote-api.jup.ag/v6/swap-instructions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            quoteResponse: quote,
            userPublicKey: agentPubkey.toString(),
            wrapAndUnwrapSol: true,
            dynamicComputeUnitLimit: true,
            prioritizationFeeLamports: 'auto'
        })
    });

    const swapInstructionsData = await swapInstructionsResponse.json();

    if (!swapInstructionsData || !swapInstructionsData.swapInstruction) {
        throw new Error(`Jupiter swap-instructions data missing or malformed: ${JSON.stringify(swapInstructionsData)}`);
    }

    // Helper to convert raw instruction data to TransactionInstruction format
    const toTransactionInstruction = (ix: any) => ({
        programId: new PublicKey(ix.programId),
        keys: ix.accounts.map((acc: any) => ({
            pubkey: new PublicKey(acc.pubkey),
            isSigner: acc.isSigner,
            isWritable: acc.isWritable,
        })),
        data: Buffer.from(ix.data, 'base64'),
    });

    // Add instructions to the transaction
    if (swapInstructionsData.computeBudgetInstructions) {
        tx.add(...swapInstructionsData.computeBudgetInstructions.map(toTransactionInstruction));
    }
    if (swapInstructionsData.setupInstructions) {
        tx.add(...swapInstructionsData.setupInstructions.map(toTransactionInstruction));
    }
    tx.add(toTransactionInstruction(swapInstructionsData.swapInstruction));
    if (swapInstructionsData.cleanupInstructions) {
        tx.add(...swapInstructionsData.cleanupInstructions.map(toTransactionInstruction));
    }

    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    return tx.serialize({ requireAllSignatures: false }).toString('base64');
}
