            quoteResponse: quote,
            userPublicKey: agentPubkey.toString(),
            wrapAndUnwrapSol: true,
            dynamicComputeUnitLimit: true,
            prioritizationFeeLamports: 'auto'
        })
    });

    const swapInstructionsData = await swapInstructionsResponse.json();

    if (!swapInstructionsData || !swapInstructionsData.swapInstruction) {
        throw new Error(`Jupiter swap-instructions data missing or malformed: ${JSON.stringify(swapInstructionsData)}`);
    }

    // Helper to convert raw instruction data to TransactionInstruction format
    const toTransactionInstruction = (ix: any) => ({
        programId: new PublicKey(ix.programId),
        keys: ix.accounts.map((acc: any) => ({
            pubkey: new PublicKey(acc.pubkey),
            isSigner: acc.isSigner,
            isWritable: acc.isWritable,
        })),
        data: Buffer.from(ix.data, 'base64'),
    });

    // Add instructions to the transaction
    if (swapInstructionsData.computeBudgetInstructions) {
        tx.add(...swapInstructionsData.computeBudgetInstructions.map(toTransactionInstruction));
    }
    if (swapInstructionsData.setupInstructions) {
        tx.add(...swapInstructionsData.setupInstructions.map(toTransactionInstruction));
    }
    tx.add(toTransactionInstruction(swapInstructionsData.swapInstruction));
    if (swapInstructionsData.cleanupInstructions) {
        tx.add(...swapInstructionsData.cleanupInstructions.map(toTransactionInstruction));
    }

    tx.recentBlockhash = blockhash;
    tx.feePayer = agentPubkey;

    return tx.serialize({ requireAllSignatures: false }).toString('base64');
}
