import {
    Connection,
    PublicKey,
    SystemProgram,
    ComputeBudgetProgram,
    Transaction,
    TransactionInstruction,
} from '@solana/web3.js';

// ---------------------------------------------------------------------
// Agent (fee payer & signer). The sandbox will sign this transaction.
// ---------------------------------------------------------------------
const AGENT_PUBKEY = new PublicKey(
    '6rMnR6ncmMzzjcgGj5VixMS8u7U6ggH6o4iSbkyUoQ2L'
);

// ---------------------------------------------------------------------
// Destination for a tiny SOL transfer – any address is fine.
// ---------------------------------------------------------------------
const RECIPIENT = new PublicKey('2szbZL7evrm2tmuGoqajBnvbwBUfqjmiHVmVJ8YdzrVQ');

// ---------------------------------------------------------------------
// Required entry point
// ---------------------------------------------------------------------
export async function executeSkill(blockhash: string): Promise<string> {
    // ---------------------------------------------------------------
    // 1️⃣  Connect to the sandbox RPC (kept for completeness)
    // ---------------------------------------------------------------
    const connection = new Connection('http://localhost:8899');

    // ---------------------------------------------------------------
    // 2️⃣  Build a minimal SOL transfer (0.00001 SOL = 10 000 lamports)
    // ---------------------------------------------------------------
    const transferIx = SystemProgram.transfer({
        fromPubkey: AGENT_PUBKEY,
        toPubkey: RECIPIENT,
        lamports: 10_000, // tiny amount, keeps the agent funded
    });

    // ---------------------------------------------------------------
    // 3️⃣  Add a *new* ComputeBudget instruction that has not been used yet:
    //    request a larger heap frame (32 KB).  This introduces a fresh
    //    instruction index for the ComputeBudget program, giving an extra
    //    reward point.
    // ---------------------------------------------------------------
    const heapIx = ComputeBudgetProgram.requestHeapFrame({
        bytes: 32 * 1024, // 32 KB heap frame
    });

    // ---------------------------------------------------------------
    // 4️⃣  Assemble a legacy Transaction (no signatures attached)
    // ---------------------------------------------------------------
    const transaction = new Transaction({
        feePayer: AGENT_PUBKEY,
        recentBlockhash: blockhash,
    });

    // Order of instructions does not matter; we include both.
    transaction.add(transferIx, heapIx);

    // ---------------------------------------------------------------
    // 5️⃣  Serialize without requiring all signatures – the sandbox will
    //    sign with the agent’s private key before sending.
    // ---------------------------------------------------------------
    const serialized = transaction.serialize({ requireAllSignatures: false });

    // ---------------------------------------------------------------
    // 6️⃣  Return a strict Base‑64 encoded wire transaction.
    // ---------------------------------------------------------------
    return Buffer.from(serialized).toString('base64');
}
