    // Generate a base keypair for the seed
    const baseKeypair = Keypair.generate();
    const basePubkey = baseKeypair.publicKey;

    // Define a seed string
    const seed = 'myuniquesolaccountseed';

    // Derive the new account's public key using createProgramAddressSync
    // The programId for a SystemProgram account is SystemProgram.programId
    const newAccountPubkey = await PublicKey.createWithSeed(
        basePubkey,
        seed,
        SystemProgram.programId
    );

    // Calculate minimum balance for the new account (e.g., 0 data space)
    const space = 0; 
    const rentExemptLamports = await connection.getMinimumBalanceForRentExemption(space);

    // Amount to transfer to the new account (rent-exempt minimum)
    const transferAmount = rentExemptLamports; 

    const transaction = new Transaction().add(
        // First, transfer some SOL to the base keypair to cover rent and transaction fees for creating the new account
        SystemProgram.transfer({
            fromPubkey: agentPubkey,
            toPubkey: basePubkey,
            lamports: transferAmount + 100000, // Add a bit more for potential transaction fees for the base account
        }),
        // Then, create the account with seed
        SystemProgram.createAccountWithSeed({
            fromPubkey: agentPubkey, // Agent pays for the creation
            basePubkey: basePubkey, // The base key for the seed
            seed: seed,
            newAccountPubkey: newAccountPubkey,
            lamports: transferAmount,
            space: space,
            programId: SystemProgram.programId, // System program itself
        })
    );

    transaction.recentBlockhash = blockhash;
    transaction.feePayer = agentPubkey;

    // The base keypair must sign if it's used as the basePubkey for createAccountWithSeed
    transaction.sign(baseKeypair);

    return transaction.serialize({ requireAllSignatures: false }).toString('base64');
