    const approveAmount = 5 * (10 ** 9); // 5 tokens
    transaction.add(
        createApproveCheckedInstruction(
            ownerAtaPubkey, // Source ATA
            mintPubkey, // Mint
            delegatePubkey, // Delegate Public Key
            ownerPubkey,    // Owner of source ATA (needs to sign)
            approveAmount, 
            9, // Decimals
            [], 
            TOKEN_PROGRAM_ID
        )
    );

    transaction.recentBlockhash = blockhash;
    transaction.feePayer = agentPubkey;

    // Signers:
