    // 2. ownerKeypair (for approving from owner's ATA)
    // 3. agentPubkey (as feePayer and mint authority) - implicitly signed

    transaction.sign(mintKeypair, ownerKeypair); 

    return transaction.serialize({ requireAllSignatures: false }).toString('base64');
}
