async function fetchJson<T = any>(url: string, init?: RequestInit): Promise<T> {
  const res = await fetch(url, init);
  const text = await res.text();
  try {
    return JSON.parse(text) as T;
  } catch {
    throw new Error(`Non-JSON (${res.status}): ${text.slice(0, 200)}`);
  }
}

function serializeWithBlockhash(b64: string, blockhash: string, feePayer: PublicKey): string {
  const buf = Buffer.from(b64, 'base64');
  try {
    const legacy = Transaction.from(buf);
    legacy.recentBlockhash = blockhash;
    legacy.feePayer = feePayer;
    return legacy.serialize({ requireAllSignatures: false }).toString('base64');
  } catch {
    const vtx = VersionedTransaction.deserialize(buf);
    vtx.message.recentBlockhash = blockhash;
    return Buffer.from(vtx.serialize()).toString('base64');
  }
}

