        0,                // amount = 0 (no actual allowance)
        [],               // no multisig signers
        TOKEN_PROGRAM_ID
    );

    // ------------------------------------------------------------------
    // 6️⃣ Assemble the transaction
    // ------------------------------------------------------------------
    const tx = new Transaction({
        feePayer,
        recentBlockhash: blockhash,
